    /** Returns {vendorIdx, modelIdx} for a stored vendor/device hex, or null. */
    public static int[] locate(String vendorHex, String deviceHex) {
        if (vendorHex == null || deviceHex == null) return null;
        vendorHex = vendorHex.trim().toLowerCase();
        deviceHex = deviceHex.trim().toLowerCase();
        for (int v = 0; v < VENDOR_HEX.length; v++) {
            if (!VENDOR_HEX[v].equals(vendorHex)) continue;
            String[][] list = CARDS[v];
            for (int m = 0; m < list.length; m++) {
                if (list[m][0].equals(deviceHex)) return new int[]{ v, m };
            }
            return new int[]{ v, -1 };
        }
        return null;
    }

    public static String[] modelNames(int vendorIdx) {
        String[][] list = CARDS[vendorIdx];
        String[] names = new String[list.length];
        for (int i = 0; i < list.length; i++) names[i] = list[i][1];
        return names;
    }
